import { getDifficultyRating } from './TeamDifficulty';

class LineupOptimizer {
    constructor(biwengerPlayers, ffProbs) {
        this.players = biwengerPlayers;
        this.ffProbs = ffProbs;
        this.positionMap = { 1: "GK", 2: "DF", 3: "MF", 4: "FW" };
        this.formations = [
            { GK: 1, DF: 3, MF: 4, FW: 3 },
            { GK: 1, DF: 3, MF: 5, FW: 2 },
            { GK: 1, DF: 4, MF: 4, FW: 2 },
            { GK: 1, DF: 4, MF: 3, FW: 3 },
            { GK: 1, DF: 4, MF: 5, FW: 1 },
            { GK: 1, DF: 5, MF: 3, FW: 2 },
            { GK: 1, DF: 5, MF: 4, FW: 1 },
        ];
    }

    _calculatePlayerScores(p) {
        const prob = parseInt(String(p.ff_prob || "0").replace("%", "")) || 0;
        const scores = (p.fitness || []).map(f => typeof f === 'number' ? f : 0);
        const avgFitness = scores.length > 0 ? scores.reduce((a, b) => a + b, 0) / scores.length : 0;

        const matchup = getDifficultyRating(p.rival_name || "", this.positionMap[p.position] || "MF");
        const matchupBonus = (6 - matchup.score) * 2;
        const trendBonus = (p.price_trend || 0) > 0 ? 1 : 0;
        const locBonus = p.location === "Home" ? 1 : 0;

        const safeScore = (prob * 0.5) + (avgFitness * 4) + matchupBonus + trendBonus + locBonus;

        const peaksBonus = (p.peaks || 0) * 10;
        const volBonus = (p.volatility || 0) * 1.5;
        const riskScore = (prob * 0.3) + (avgFitness * 2) + peaksBonus + volBonus + matchupBonus;

        return {
            safe: Math.round(safeScore * 100) / 100,
            risk: Math.round(riskScore * 100) / 100,
            dvp_label: matchup.label
        };
    }

    matchPlayers() {
        const enriched = this.players.map(p => {
            // Smart match within FF data
            let foundProb = "Unknown";
            const nameLower = p.name.toLowerCase();
            const nameParts = nameLower.split(" ").filter(part => part.length > 2);

            for (const [ffName, prob] of Object.entries(this.ffProbs)) {
                const ffLower = ffName.toLowerCase();
                if (nameLower.includes(ffLower) || ffLower.includes(nameLower) || nameParts.some(part => ffLower.includes(part))) {
                    foundProb = prob;
                    break;
                }
            }

            p.ff_prob = foundProb;
            const scores = this._calculatePlayerScores(p);
            p.safe_score = scores.safe;
            p.risk_score = scores.risk;
            p.dvp_label = scores.dvp_label;
            p.pos_name = this.positionMap[p.position] || "Unknown";
            p.all_pos_names = (p.positions || [p.position]).map(pos => this.positionMap[pos] || "Unknown");

            return p;
        });
        return enriched;
    }

    solve(players, strategy = "safe") {
        const scoreKey = strategy === "safe" ? "safe_score" : "risk_score";

        for (const threshold of [50, 40, 30, 20, 10, 0]) {
            const validSquad = players.filter(p => {
                const prob = parseInt(String(p.ff_prob || "0").replace("%", "")) || 0;
                return prob >= threshold && p.status !== "injured";
            });

            if (validSquad.length < 11) continue;

            let bestOverallScore = -1;
            let bestLineup = [];
            let bestFormName = "";

            for (const form of this.formations) {
                let available = [...validSquad];
                let potential = [];

                // Helper to pick top N for a role
                const pick = (role, count) => {
                    const candidates = available
                        .filter(p => p.all_pos_names.includes(role))
                        .sort((a, b) => b[scoreKey] - a[scoreKey])
                        .slice(0, count);

                    if (candidates.length < count) return false;

                    candidates.forEach(c => {
                        potential.push(c);
                        available = available.filter(ap => ap.id !== c.id);
                    });
                    return true;
                };

                if (!pick("GK", 1)) continue;
                if (!pick("DF", form.DF)) continue;
                if (!pick("MF", form.MF)) continue;
                if (!pick("FW", form.FW)) continue;

                const totalScore = potential.reduce((sum, p) => sum + p[scoreKey], 0);
                if (totalScore > bestOverallScore) {
                    bestOverallScore = totalScore;
                    bestLineup = potential;
                    bestFormName = `${form.DF}-${form.MF}-${form.FW}`;
                }
            }

            if (bestLineup.length === 11) {
                return { lineup: bestLineup, formation: bestFormName };
            }
        }
        return { lineup: [], formation: "" };
    }
}

export default LineupOptimizer;
